14 <span style="color:#8b008b;font-weight:bold">public</span> <span style="color:#8b008b;font-weight:bold">class</span> <span style="color:#008b45;font-weight:bold">Test</span> {
15
16     <span style="color:#228b22">/**
</span><span style="color:#228b22">17      * @param args
</span><span style="color:#228b22">18      * @throws ServiceException
</span><span style="color:#228b22">19      * @throws MalformedURLException
</span><span style="color:#228b22">20      * @throws RemoteException
</span><span style="color:#228b22">21      */</span>
22     <span style="color:#8b008b;font-weight:bold">public</span> <span style="color:#8b008b;font-weight:bold">static</span> <span style="color:#00688b;font-weight:bold">void</span> <span style="color:#008b45">main</span>(String[] args) <span style="color:#8b008b;font-weight:bold">throws</span> ServiceException, RemoteException {
23
24         <span style="color:#228b22">//WSDL地址
</span><span style="color:#228b22"></span>25         String wsdlUrl =<span style="color:#cd5555">&#34;http://IP:PORT/ExampleWebService?wsdl&#34;</span>;  
26         <span style="color:#228b22">//看具体响应的WSDL中的namespace
</span><span style="color:#228b22"></span>27         String nameSpaceUri =<span style="color:#cd5555">&#34;http://ws.exmaple.com/&#34;</span>;
