</span><span style="color:#228b22"></span>35         call.<span style="color:#658b00">setOperationName</span>(<span style="color:#8b008b;font-weight:bold">new</span> QName(nameSpaceUri, <span style="color:#cd5555">&#34;order&#34;</span>));
36
37         <span style="color:#228b22">//设置账户，注意参数为XSD_STRRING
</span><span style="color:#228b22"></span>38         call.<span style="color:#658b00">addParameter</span>(<span style="color:#cd5555">&#34;account&#34;</span>, org.<span style="color:#658b00">apache</span>.<span style="color:#658b00">axis</span>.<span style="color:#658b00">Constants</span>.<span style="color:#658b00">XSD_STRING</span>,
39                 ParameterMode.<span style="color:#658b00">IN</span>);
40
41         <span style="color:#228b22">//设置账户，注意参数为XSD_LONG
</span><span style="color:#228b22"></span>42         call.<span style="color:#658b00">addParameter</span>(<span style="color:#cd5555">&#34;price&#34;</span>, org.<span style="color:#658b00">apache</span>.<span style="color:#658b00">axis</span>.<span style="color:#658b00">Constants</span>.<span style="color:#658b00">XSD_LONG</span>,
43                 ParameterMode.<span style="color:#658b00">IN</span>);
44
45         <span style="color:#228b22">//设置返回类型为对象数组
</span><span style="color:#228b22"></span>46         call.<span style="color:#658b00">setReturnClass</span>(Object[].<span style="color:#658b00">class</span>);
47
48         Object[] result = (Object[]) call.<span style="color:#658b00">invoke</span>(<span style="color:#8b008b;font-weight:bold">new</span> Object[]{<span style="color:#cd5555">&#34;test&#34;</span>,<span style="color:#cd5555">&#34;123456&#34;</span>});
49
50         System.<span style="color:#658b00">out</span>.<span style="color:#658b00">println</span>(result[0]);
51
52     }
53
54 }
</code></pre></div><p>常见异常：</p>
<p>1.org.xml.sax.SAXException: No deserializer for {<a href="http://www.w3.org/2001/XMLSchema%7DanyType">http://www.w3.org/2001/XMLSchema}anyType</a></p>
<p>　　这个异常需要检查 call.setReturnClass(); 中的类型，或者是 setReturnType()</p>
<ol>
<li>Unexpected wrapper element order found.</li>
</ol>
<p>　可以检查 setOperationName 中的 QName 参数，其中的 NameSpace 地址是不是有问题，或者 operation 名是否有误</p>
